const body = $input.first().json.body;
const entry = body?.entry?.[0];
const changes = entry?.changes?.[0];
const value = changes?.value;
const message = value?.messages?.[0];

if (!message) {
  return [{ json: { skip: true } }];
}

const from = message.from;
const messageId = message.id;
const text = message.text?.body || '';
const timestamp = message.timestamp;

const contact = value?.contacts?.[0];
const customerName = contact?.profile?.name || 'Cliente';

return [{
  json: {
    from,
    messageId,
    text,
    timestamp,
    customerName,
    skip: false
  }
}];

const menu = $('Obtener Menú Disponible').item.json;
const pizzas = menu.filter(i => i.category === 'pizza');
const bebidas = menu.filter(i => i.category === 'bebida');

const formatPrice = (cents) => cents ? `S/.${(cents/100).toFixed(0)}` : null;

const menuText = `
PIZZAS:
${pizzas.map(p => `- ${p.name}${p.description ? ' (' + p.description + ')' : ''}: Pequeña ${formatPrice(p.priceSmall) || 'N/A'} | Mediana ${formatPrice(p.priceMedium) || 'N/A'} | Grande ${formatPrice(p.priceLarge) || 'N/A'}`).join('\n')}

BEBIDAS:
${bebidas.map(b => `- ${b.name}: ${formatPrice(b.priceSmall)}`).join('\n')}
`;

const customers = $('Buscar Cliente Existente').item.json;
const isExistingCustomer = Array.isArray(customers) && customers.length > 0;
const customer = isExistingCustomer ? customers[0] : null;

return [{
  json: {
    menuText,
    isExistingCustomer,
    customerAddress: customer?.address || null,
    customerName: $('Extraer Mensaje WhatsApp').item.json.customerName
  }
}];

const aiResponse = $input.first().json.message.content;

let parsedOrder = null;
let isConfirmedOrder = false;
let clientMessage = aiResponse;

// Try to detect if AI returned a confirmed order JSON
try {
  const jsonMatch = aiResponse.match(/```json([\s\S]*?)```/);
  if (jsonMatch) {
    const parsed = JSON.parse(jsonMatch[1].trim());
    if (parsed.tipo === 'PEDIDO_CONFIRMADO') {
      isConfirmedOrder = true;
      parsedOrder = parsed;
      clientMessage = parsed.mensajeCliente;
    }
  }
} catch(e) {
  // Not a JSON, it's a conversational response
}

return [{
  json: {
    isConfirmedOrder,
    parsedOrder,
    clientMessage,
    from: $('Extraer Mensaje WhatsApp').item.json.from,
    customerName: $('Extraer Mensaje WhatsApp').item.json.customerName,
    messageId: $('Extraer Mensaje WhatsApp').item.json.messageId
  }
}];
